   193	    private List<String> generatePriorityNames(String name,
   194	        Map<Locality, LocalityLbEndpoints> localityLbEndpoints) {
   195	      TreeMap<Integer, List<Locality>> todo = new TreeMap<>();
   196	      for (Locality locality : localityLbEndpoints.keySet()) {
   197	        int priority = localityLbEndpoints.get(locality).priority();
   198	        if (!todo.containsKey(priority)) {
   199	          todo.put(priority, new ArrayList<>());
   200	        }
   201	        todo.get(priority).add(locality);
   202	      }
   203	      Map<Locality, String> newNames = new HashMap<>();
   204	      Set<String> usedNames = new HashSet<>();
   205	      List<String> ret = new ArrayList<>();
   206	      for (Integer priority: todo.keySet()) {
   207	        String foundName = "";
   208	        for (Locality locality : todo.get(priority)) {
   209	          if (localityPriorityNames.containsKey(locality)
   210	              && usedNames.add(localityPriorityNames.get(locality))) {
   211	            foundName = localityPriorityNames.get(locality);
   212	            break;
   213	          }
   214	        }
   215	        if ("".equals(foundName)) {
   216	          foundName = priorityName(name, priorityNameGenId++);
   217	        }
   218	        for (Locality locality : todo.get(priority)) {
   219	          newNames.put(locality, foundName);
   220	        }
   221	        ret.add(foundName);
   222	      }
   223	      localityPriorityNames = newNames;
   224	      return ret;
   225	    }
   226	  }
