   228	  private static class ClusterResolutionResult {
   229	    // Endpoint addresses.
   230	    private final List<EquivalentAddressGroup> addresses;
   231	    // Config (include load balancing policy/config) for each priority in the cluster.
   232	    private final Map<String, PriorityChildConfig> priorityChildConfigs;
   233	    // List of priority names ordered in descending priorities.
   234	    private final List<String> priorities;
