   244	  /**
   245	   * Generates configs to be used in the priority LB policy for priorities in a cluster.
   246	   *
   247	   * <p>priority LB -> cluster_impl LB (one per priority) -> (weighted_target LB
   248	   * -> round_robin / least_request_experimental (one per locality)) / ring_hash_experimental
   249	   */
   250	  private static Map<String, PriorityChildConfig> generatePriorityChildConfigs(
   251	      String clusterName,
   252	      CdsUpdate discovery,
   253	      Object endpointLbConfig,
   254	      LoadBalancerRegistry lbRegistry,
   255	      Map<String, Map<Locality, Integer>> prioritizedLocalityWeights,
   256	      List<DropOverload> dropOverloads) {
   257	    Map<String, PriorityChildConfig> configs = new HashMap<>();
   258	    for (String priority : prioritizedLocalityWeights.keySet()) {
   259	      ClusterImplConfig clusterImplConfig =
   260	          new ClusterImplConfig(
   261	              clusterName, discovery.edsServiceName(), discovery.lrsServerInfo(),
   262	              discovery.maxConcurrentRequests(), dropOverloads, endpointLbConfig,
   263	              discovery.upstreamTlsContext(), discovery.filterMetadata(),
   264	              discovery.backendMetricPropagation());
   265	      LoadBalancerProvider clusterImplLbProvider =
   266	          lbRegistry.getProvider(XdsLbPolicies.CLUSTER_IMPL_POLICY_NAME);
   267	      Object priorityChildPolicy = GracefulSwitchLoadBalancer.createLoadBalancingPolicyConfig(
   268	          clusterImplLbProvider, clusterImplConfig);
   269	
   270	      // If outlier detection has been configured we wrap the child policy in the outlier detection
   271	      // load balancer.
   272	      if (discovery.outlierDetection() != null) {
   273	        LoadBalancerProvider outlierDetectionProvider = lbRegistry.getProvider(
   274	            "outlier_detection_experimental");
   275	        priorityChildPolicy = GracefulSwitchLoadBalancer.createLoadBalancingPolicyConfig(
   276	            outlierDetectionProvider,
   277	            buildOutlierDetectionLbConfig(discovery.outlierDetection(), priorityChildPolicy));
   278	      }
   279	
   280	      boolean isEds = discovery.clusterType() == ClusterType.EDS;
   281	      PriorityChildConfig priorityChildConfig =
   282	          new PriorityChildConfig(priorityChildPolicy, isEds /* ignoreReresolution */);
   283	      configs.put(priority, priorityChildConfig);
   284	    }
   285	    return configs;
   286	  }
