   288	  /**
   289	   * Converts {@link OutlierDetection} that represents the xDS configuration to {@link
   290	   * OutlierDetectionLoadBalancerConfig} that the {@link io.grpc.util.OutlierDetectionLoadBalancer}
   291	   * understands.
   292	   */
   293	  private static OutlierDetectionLoadBalancerConfig buildOutlierDetectionLbConfig(
   294	      OutlierDetection outlierDetection, Object childConfig) {
   295	    OutlierDetectionLoadBalancerConfig.Builder configBuilder
   296	        = new OutlierDetectionLoadBalancerConfig.Builder();
   297	
   298	    configBuilder.setChildConfig(childConfig);
   299	
   300	    if (outlierDetection.intervalNanos() != null) {
   301	      configBuilder.setIntervalNanos(outlierDetection.intervalNanos());
   302	    }
   303	    if (outlierDetection.baseEjectionTimeNanos() != null) {
   304	      configBuilder.setBaseEjectionTimeNanos(outlierDetection.baseEjectionTimeNanos());
   305	    }
   306	    if (outlierDetection.maxEjectionTimeNanos() != null) {
   307	      configBuilder.setMaxEjectionTimeNanos(outlierDetection.maxEjectionTimeNanos());
   308	    }
   309	    if (outlierDetection.maxEjectionPercent() != null) {
   310	      configBuilder.setMaxEjectionPercent(outlierDetection.maxEjectionPercent());
   311	    }
   312	
   313	    SuccessRateEjection successRate = outlierDetection.successRateEjection();
   314	    if (successRate != null) {
   315	      OutlierDetectionLoadBalancerConfig.SuccessRateEjection.Builder
   316	          successRateConfigBuilder = new OutlierDetectionLoadBalancerConfig
   317	          .SuccessRateEjection.Builder();
   318	
   319	      if (successRate.stdevFactor() != null) {
   320	        successRateConfigBuilder.setStdevFactor(successRate.stdevFactor());
   321	      }
   322	      if (successRate.enforcementPercentage() != null) {
   323	        successRateConfigBuilder.setEnforcementPercentage(successRate.enforcementPercentage());
   324	      }
   325	      if (successRate.minimumHosts() != null) {
   326	        successRateConfigBuilder.setMinimumHosts(successRate.minimumHosts());
   327	      }
   328	      if (successRate.requestVolume() != null) {
   329	        successRateConfigBuilder.setRequestVolume(successRate.requestVolume());
   330	      }
   331	
   332	      configBuilder.setSuccessRateEjection(successRateConfigBuilder.build());
   333	    }
   334	
   335	    FailurePercentageEjection failurePercentage = outlierDetection.failurePercentageEjection();
   336	    if (failurePercentage != null) {
   337	      OutlierDetectionLoadBalancerConfig.FailurePercentageEjection.Builder
   338	          failurePercentageConfigBuilder = new OutlierDetectionLoadBalancerConfig
   339	          .FailurePercentageEjection.Builder();
   340	
   341	      if (failurePercentage.threshold() != null) {
   342	        failurePercentageConfigBuilder.setThreshold(failurePercentage.threshold());
   343	      }
   344	      if (failurePercentage.enforcementPercentage() != null) {
   345	        failurePercentageConfigBuilder.setEnforcementPercentage(
   346	            failurePercentage.enforcementPercentage());
   347	      }
   348	      if (failurePercentage.minimumHosts() != null) {
   349	        failurePercentageConfigBuilder.setMinimumHosts(failurePercentage.minimumHosts());
   350	      }
   351	      if (failurePercentage.requestVolume() != null) {
   352	        failurePercentageConfigBuilder.setRequestVolume(failurePercentage.requestVolume());
   353	      }
   354	
   355	      configBuilder.setFailurePercentageEjection(failurePercentageConfigBuilder.build());
   356	    }
   357	
   358	    return configBuilder.build();
   359	  }
